import { describe, expect, test } from '@a0n/gnosis/test';
import {
  SEISMIC_STRESS_TOY_DISCLAIMER,
  effectiveCriticalLinear,
  normalizeRateStateAsperityParams,
  normalizeSingleAsperityParams,
  rateStateThetaAging,
  relaxTwoPatch,
  simulateSingleAsperity,
  simulateCoupledTwoPatch,
  simulateCoupledTwoPatchRateState,
  simulateSingleAsperityRateState,
  slipAfterLoaded,
  stepCoupledTwoPatch,
  stepCoupledTwoPatchRateState,
  stepMultiAsperity,
  stepSingleAsperity,
  stepSingleAsperityRateState,
} from '../seismic-stress-toy';

describe('seismic-stress-toy', () => {
  test('disclaimer names the epistemic boundary', () => {
    expect(SEISMIC_STRESS_TOY_DISCLAIMER).toContain('not a continuum');
  });

  test('stepSingleAsperity loads without rupture when below threshold', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 10,
      loadingRate: 1,
      stressDrop: 5,
      residualStress: 0,
      mode: 'subtract',
    });
    const r = stepSingleAsperity(5, p);
    expect(r.stress).toBeCloseTo(6);
    expect(r.rupture).toBeNull();
  });

  test('stepSingleAsperity subtract mode releases stress with floor', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 10,
      loadingRate: 2,
      stressDrop: 8,
      residualStress: 1,
      mode: 'subtract',
    });
    const r = stepSingleAsperity(9, p);
    expect(r.rupture).not.toBeNull();
    expect(r.rupture!.stressBeforeSlip).toBeCloseTo(11);
    expect(r.stress).toBeCloseTo(3);
  });

  test('stepSingleAsperity reset mode snaps to residual', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 5,
      loadingRate: 1,
      stressDrop: 99,
      residualStress: 0.25,
      mode: 'reset',
    });
    const r = stepSingleAsperity(5, p);
    expect(r.stress).toBeCloseTo(0.25);
    expect(r.rupture!.stressAfterSlip).toBeCloseTo(0.25);
  });

  test('simulateSingleAsperity records periodic ruptures under steady loading', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 10,
      loadingRate: 3,
      stressDrop: 7,
      residualStress: 0,
      mode: 'subtract',
    });
    const { ruptures } = simulateSingleAsperity(0, p, 20);
    const hits = ruptures.filter((x) => x !== null).length;
    expect(hits).toBeGreaterThanOrEqual(2);
  });

  test('slipAfterLoaded matches stepSingleAsperity after manual load', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 5,
      loadingRate: 2,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const a = stepSingleAsperity(3, p);
    const b = slipAfterLoaded(3 + p.loadingRate, p);
    expect(a.stress).toBeCloseTo(b.stress);
    expect(Boolean(a.rupture)).toBe(Boolean(b.rupture));
  });

  test('relaxTwoPatch conserves total stress', () => {
    const { m0, m1 } = relaxTwoPatch(10, 4, 0.25);
    expect(m0 + m1).toBeCloseTo(14);
  });

  test('relaxTwoPatch conserves for several loads (Lean `relax_two_patch_real_conserves`)', () => {
    for (const l0 of [0, 1.5, 10]) {
      for (const l1 of [2, 3.25]) {
        for (const k of [0, 0.1, 0.49, 0.75, 1]) {
          const { m0, m1 } = relaxTwoPatch(l0, l1, k);
          expect(m0 + m1).toBeCloseTo(l0 + l1);
        }
      }
    }
  });

  test('rateStateThetaAging and effectiveCriticalLinear are finite hooks', () => {
    const th = rateStateThetaAging(0.1, 1, 0.05);
    expect(th).toBeCloseTo(0.15);
    expect(effectiveCriticalLinear(10, 2, th)).toBeCloseTo(10 + 2 * th);
  });

  test('stepSingleAsperityRateState with b=0 matches fixed critical', () => {
    const fixed = normalizeSingleAsperityParams({
      criticalStress: 10,
      loadingRate: 1,
      stressDrop: 3,
      residualStress: 0,
      mode: 'subtract',
    });
    const rs = normalizeRateStateAsperityParams({
      critical0: 10,
      b: 0,
      agingRate: 0.01,
      dt: 1,
      loadingRate: 1,
      stressDrop: 3,
      residualStress: 0,
      mode: 'subtract',
    });
    const a = stepSingleAsperity(5, fixed);
    const b = stepSingleAsperityRateState(5, 0, rs);
    expect(a.stress).toBeCloseTo(b.stress);
    expect(b.theta).toBeCloseTo(0.01);
  });

  test('thetaOnRupture resets θ after slip', () => {
    const p = normalizeRateStateAsperityParams({
      critical0: 5,
      b: 0,
      agingRate: 10,
      dt: 1,
      loadingRate: 10,
      stressDrop: 5,
      residualStress: 0,
      mode: 'subtract',
      thetaOnRupture: 0,
    });
    const r = stepSingleAsperityRateState(0, 0, p);
    expect(r.rupture).not.toBeNull();
    expect(r.theta).toBe(0);
  });

  test('relaxTwoPatch keeps nonnegative loads nonnegative for kappa<=1 (Lean nonneg lemma)', () => {
    const l0 = 3;
    const l1 = 11;
    for (const k of [0.5, 1]) {
      const { m0, m1 } = relaxTwoPatch(l0, l1, k);
      expect(m0).toBeGreaterThanOrEqual(0);
      expect(m1).toBeGreaterThanOrEqual(0);
    }
  });

  test('simulateCoupledTwoPatch matches repeated stepCoupledTwoPatch', () => {
    const p = normalizeSingleAsperityParams({
      criticalStress: 50,
      loadingRate: 0,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const coupled = { kappa: 0.2, patch0: p, patch1: p };
    const sim = simulateCoupledTwoPatch(10, 20, coupled, 4);
    expect(sim.stresses0.length).toBe(5);
    let σ0 = 10;
    let σ1 = 20;
    for (let i = 0; i < 4; i++) {
      const st = stepCoupledTwoPatch(σ0, σ1, coupled);
      σ0 = st.stress0;
      σ1 = st.stress1;
    }
    expect(sim.stresses0[sim.stresses0.length - 1]).toBeCloseTo(σ0);
    expect(sim.stresses1[sim.stresses1.length - 1]).toBeCloseTo(σ1);
  });

  test('simulateCoupledTwoPatchRateState matches repeated stepCoupledTwoPatchRateState', () => {
    const rs = normalizeRateStateAsperityParams({
      critical0: 50,
      b: 0,
      agingRate: 0,
      dt: 1,
      loadingRate: 0,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const coupled = { kappa: 0.2, patch0: rs, patch1: rs };
    const sim = simulateCoupledTwoPatchRateState(10, 20, 0, 0, coupled, 4);
    expect(sim.stresses0.length).toBe(5);
    let σ0 = 10;
    let σ1 = 20;
    let θ0 = 0;
    let θ1 = 0;
    for (let i = 0; i < 4; i++) {
      const st = stepCoupledTwoPatchRateState(σ0, σ1, θ0, θ1, coupled);
      σ0 = st.stress0;
      σ1 = st.stress1;
      θ0 = st.theta0;
      θ1 = st.theta1;
    }
    expect(sim.stresses0[sim.stresses0.length - 1]).toBeCloseTo(σ0);
    expect(sim.stresses1[sim.stresses1.length - 1]).toBeCloseTo(σ1);
  });

  test('stepCoupledTwoPatchRateState with kappa=0 matches independent rate-state steps', () => {
    const rs = normalizeRateStateAsperityParams({
      critical0: 100,
      b: 0,
      agingRate: 0,
      dt: 1,
      loadingRate: 1,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const c = stepCoupledTwoPatchRateState(5, 20, 0, 0, { kappa: 0, patch0: rs, patch1: rs });
    const u0 = stepSingleAsperityRateState(5, 0, rs);
    const u1 = stepSingleAsperityRateState(20, 0, rs);
    expect(c.stress0).toBeCloseTo(u0.stress);
    expect(c.stress1).toBeCloseTo(u1.stress);
    expect(c.theta0).toBeCloseTo(u0.theta);
    expect(c.theta1).toBeCloseTo(u1.theta);
  });

  test('simulateSingleAsperityRateState increases theta each step', () => {
    const p = normalizeRateStateAsperityParams({
      critical0: 100,
      b: 0,
      agingRate: 1,
      dt: 1,
      loadingRate: 0,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const { thetas } = simulateSingleAsperityRateState(0, 0, p, 5);
    expect(thetas[thetas.length - 1]).toBeCloseTo(5);
  });

  test('stepCoupledTwoPatch can delay rupture via stress transfer', () => {
    const pNear = normalizeSingleAsperityParams({
      criticalStress: 10,
      loadingRate: 1,
      stressDrop: 5,
      residualStress: 0,
      mode: 'subtract',
    });
    const pFar = normalizeSingleAsperityParams({
      criticalStress: 100,
      loadingRate: 0,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const uncoupled = stepMultiAsperity([9, 2], { patches: [pNear, pFar] });
    expect(uncoupled.ruptures[0]).not.toBeNull();
    const coupled = stepCoupledTwoPatch(9, 2, {
      kappa: 0.25,
      patch0: pNear,
      patch1: pFar,
    });
    expect(coupled.rupture0).toBeNull();
  });

  test('stepMultiAsperity runs patches independently', () => {
    const a = normalizeSingleAsperityParams({
      criticalStress: 100,
      loadingRate: 1,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const b = normalizeSingleAsperityParams({
      criticalStress: 1,
      loadingRate: 1,
      stressDrop: 1,
      residualStress: 0,
      mode: 'subtract',
    });
    const r = stepMultiAsperity([0, 0], { patches: [a, b] });
    expect(r.ruptures[0]).toBeNull();
    expect(r.ruptures[1]).not.toBeNull();
  });
});
